#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
string L,R;
LL dp[15][2][2][2][2][5][10],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    cin>>L>>R;//输入上下界
    memset(dp,0,sizeof(dp));//清空 DP 数组
    dp[0][0][0][0][0][0][0]=1;//赋初值
    for(int i=0;i<11;i++)for(int x=0;x<2;x++)//枚举
    for(int y=0;y<2;y++)for(int u=0;u<2;u++)//枚举
    for(int v=0;v<2;v++)for(int c=0;c<4;c++)for(int k=0;k<10;k++)//枚举
    for(int j=(x?0:L[i]-'0');j<=(y?9:R[i]-'0');j++){//枚举
        int nx=(x||(j>(L[i]-'0')));//计算 new_x
        int ny=(y||(j<(R[i]-'0')));//计算 new_y
        int nu=(u||j==8);//计算 new_u
        int nv=(v||j==4);//计算 new_v
        int nc=(c==3?3:(j==k?c+1:1));//计算 new_c
        dp[i+1][nx][ny][nu][nv][nc][j]+=dp[i][x][y][u][v][c][k];//转移
    }
    Ans=0;//清零 Ans
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)
        for(int u=0;u<2;u++)for(int v=0;v<2-u;v++)
            for(int k=0;k<10;k++)Ans+=dp[11][x][y][u][v][3][k];//计算
    cout<<Ans<<"\n";//输出答案
    return 0;
}
